#include <stdio.h>
int main() {
    int T, S;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &S);
        if (S > 40) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

